from matplotlib.patches import Rectanglefrom .utils import *from criresviz.plotting.style import (    ZORDER,    BAR_HEIGHT,    MOLECULE_TEXT_SIZE,    MOLECULE_COLORS,          )"""--------------------------------------------------------------------------------------------------------- Low-level drawing functions for molecular absorption regions. ------------------------------------------------------------------------------------------------------------"""def _draw_molecule_label(ax, molecule, rectangle, y):    """    Draw the label associated with a molecular absorption bar.    Parameters    ----------    ax : matplotlib.axes.Axes        Axis on which to draw.    molecule : Molecule        Molecule being displayed.    rectangle : matplotlib.patches.Rectangle        Rectangle corresponding to the last visible active region.    y : float        Vertical position of the label in axes coordinates.    """      ax.text(        rectangle.xy[0] + rectangle._width / 2,        y + 0.02,        str(molecule.name),        ha="center",        va="center",        zorder=ZORDER["labels"],        color=MOLECULE_COLORS.get(molecule.name),        fontweight="bold",        fontsize=MOLECULE_TEXT_SIZE,    )##############################################def _draw_molecule(molecule, ax, y=1.05, clip=False):    """    Draw the active wavelength regions of a molecule.    Parameters    ----------    molecule : Molecule        Molecule to display.    ax : matplotlib.axes.Axes        Axis on which to draw.    y : float, optional        Vertical position of the molecule bar in axes coordinates.    clip : bool, optional        Whether the bars should be clipped to the plotting area.    Returns    -------    matplotlib.axes.Axes        The modified axes.    """        if not ax.has_data():        xmin, xmax = molecule.wavelength_range        ax.set_xlim(xmin, xmax)        ax.set_yticks([])        xmin, xmax = ax.get_xlim()            regions = molecule.active_regions                last_rectangle = None        for start, end in regions:            if end < xmin or start > xmax:            continue            start = max(start, xmin)        end   = min(end, xmax)            last_rectangle = Rectangle(            (start, y),            end - start,            BAR_HEIGHT,            facecolor=MOLECULE_COLORS.get(molecule.name, "gray"),            zorder=ZORDER["molecule"],            clip_on=clip,        )                    ax.add_patch(last_rectangle)                if last_rectangle is not None:        _draw_molecule_label(ax, molecule, last_rectangle, y)                return ax